use std::io::stdin;
fn main() {
    let mut text = String::new();
    stdin().read_line(&mut text).unwrap();
    let text: Vec<&str> = text.trim().split_whitespace().collect();
    let mut value = 0;

    let mut val: Vec<String> = vec![];
    let a = text[0].chars().collect::<Vec<char>>();
    let b = text[1].chars().collect::<Vec<char>>();
    let mut text1 = String::new();
    for x in &a {
        text1.push(*x);
        let mut text2 = String::new();

        for y in &b {
            text2.push(*y);
            val.push(text1.clone() + &text2[..]);
        }
    }
    val.sort();
    println!("{}", val[0]);
}
